export function GlobalAlloc(flags, size) {
  // Bump-allocate from top of _MEM buffer
  const aligned = (size + 15) & ~15; // 16-byte align
  _heapPtr -= aligned;
  if (_heapPtr < G._MEM.length / 2) {
    console.error('GlobalAlloc: heap exhausted at', _heapPtr);
    return 0;
  }
  const handle = _heapPtr; // use ptr as handle
  _heapAllocs.set(handle, { ptr: _heapPtr, size: aligned });
  // Zero the allocated region
  G._MEM.fill(0, _heapPtr, _heapPtr + aligned);
  return handle;
}
export function GlobalCompact(...args) { return stubCall('GlobalCompact', args); }
export function GlobalFree(handle) {
  _heapAllocs.delete(handle);
  return 0;
}
