export function GlobalLock(handle) {
  // Returns the pointer (same as handle in our model)
  const alloc = _heapAllocs.get(handle);
  return alloc ? alloc.ptr : handle;
}
export function GlobalSize(handle) {
  const alloc = _heapAllocs.get(handle);
  return alloc ? alloc.size : 0;
}
